  1→import { useEffect, useState } from 'react';
  2→import AnnotationRenderer from './AnnotationRenderer';
  3→import BeamRenderer from './BeamRenderer';
  4→import ColumnRenderer from './ColumnRenderer';
  5→import DoorRenderer from './DoorRenderer';
  6→import ElevationSceneLayer from './ElevationSceneLayer';
  7→import LandingRenderer from './LandingRenderer';
  8→import RoomRenderer from './RoomRenderer';
  9→import SectionCutRenderer from './SectionCutRenderer';
 10→import SectionSceneLayer from './SectionSceneLayer';
 11→import SlabRenderer from './SlabRenderer';
 12→import StairRenderer from './StairRenderer';
 13→import WallRenderer from './WallRenderer';
 14→import WindowRenderer from './WindowRenderer';
 15→
 16→const SHEET_PREVIEW_OPTIONS = {
 17→  width: 1600,
 18→  height: 1000,
 19→  preset: 'iso_northeast',
 20→};
 21→const sheetPreviewCache = new Map();
 22→
 23→function getSheetPreviewCacheKey(source) {
 24→  return [
 25→    source?.project?.id || 'project',
 26→    source?.project?.updatedAt || 'snapshot',
 27→    source?.activeFloorId || 'all',
 28→    SHEET_PREVIEW_OPTIONS.width,
 29→    SHEET_PREVIEW_OPTIONS.height,
 30→    SHEET_PREVIEW_OPTIONS.preset,
 31→  ].join(':');
 32→}
 33→
 34→function renderSheetPreviewImage(source) {
 35→  const cacheKey = getSheetPreviewCacheKey(source);
 36→  if (!sheetPreviewCache.has(cacheKey)) {
 37→    sheetPreviewCache.set(cacheKey, import('@/three/viewer/renderToImage')
 38→      .then(({ renderSceneToImage }) => {
 39→        const imageUrl = renderSceneToImage(source.project, {
 40→          activeFloorId: source.activeFloorId,
 41→          width: SHEET_PREVIEW_OPTIONS.width,
 42→          height: SHEET_PREVIEW_OPTIONS.height,
 43→          preset: SHEET_PREVIEW_OPTIONS.preset,
 44→        });
 45→
 46→        return imageUrl
 47→          ? { status: 'ready', imageUrl }
 48→          : { status: 'empty', imageUrl: null };
 49→      })
 50→      .catch((error) => {
 51→        sheetPreviewCache.delete(cacheKey);
 52→        throw error;
 53→      }));
 54→  }
 55→
 56→  return sheetPreviewCache.get(cacheKey);
 57→}
 58→
 59→function PlanViewportContent({ floor }) {
 60→  return (
 61→    <>
 62→      {(floor.slabs || []).map(slab => (
 63→        <SlabRenderer key={slab.id} slab={slab} selectedId={null} />
 64→      ))}
 65→      <RoomRenderer rooms={floor.rooms} selectedId={null} interactive={false} />
 66→      <WallRenderer walls={floor.walls} columns={floor.columns || []} />
 67→      <BeamRenderer beams={floor.beams || []} columns={floor.columns || []} />
 68→      <StairRenderer stairs={floor.stairs || []} />
 69→      <LandingRenderer landings={floor.landings || []} />
 70→      <ColumnRenderer columns={floor.columns || []} />
 71→      <DoorRenderer doors={floor.doors} walls={floor.walls} />
 72→      <WindowRenderer windows={floor.windows} walls={floor.walls} />
 73→      {(floor.sectionCuts || []).map(sc => (
 74→        <SectionCutRenderer key={sc.id} sectionCut={sc} selectedId={null} />
 75→      ))}
 76→      <AnnotationRenderer floor={floor} />
 77→    </>
 78→  );
 79→}
 80→
 81→function ThreePreviewViewportContent({ source }) {
 82→  const [previewState, setPreviewState] = useState({
 83→    status: 'loading',
 84→    imageUrl: null,
 85→  });
 86→
 87→  useEffect(() => {
 88→    if (!source?.project) {
 89→      setPreviewState({
 90→        status: 'empty',
 91→        imageUrl: null,
 92→      });
 93→      return undefined;
 94→    }
 95→
 96→    let cancelled = false;
 97→    setPreviewState({
 98→      status: 'loading',
 99→      imageUrl: null,
100→    });
101→
102→    renderSheetPreviewImage(source)
103→      .then((result) => {
104→        if (cancelled) return;
105→        setPreviewState(result);
106→      })
107→      .catch((error) => {
108→        if (cancelled) return;
109→        console.error('Failed to render sheet 3D preview:', error);
110→        setPreviewState({
111→          status: 'error',
112→          imageUrl: null,
113→        });
114→      });
115→
116→    return () => { cancelled = true; };
117→  }, [source?.project, source?.project?.updatedAt, source?.activeFloorId]);
118→
119→  const { bounds } = source;
120→  const centerX = (bounds.minX + bounds.maxX) / 2;
121→  const centerY = (bounds.minY + bounds.maxY) / 2;
122→
123→  if (previewState.status !== 'ready' || !previewState.imageUrl) {
124→    const messages = {
125→      loading: 'Rendering 3D preview...',
126→      empty: 'No 3D geometry available.',
127→      error: '3D preview failed to render.',
128→    };
129→
130→    return (
131→      <text
132→        x={centerX}
133→        y={centerY}
134→        textAnchor="middle"
135→        fontSize={400}
136→        fill="#8899aa"
137→        pointerEvents="none"
138→      >
139→        {messages[previewState.status] || messages.loading}
140→      </text>
141→    );
142→  }
143→
144→  return (
145→    <image
146→      href={previewState.imageUrl}
147→      x={bounds.minX}
148→      y={bounds.minY}
149→      width={bounds.maxX - bounds.minX}
150→      height={bounds.maxY - bounds.minY}
151→      preserveAspectRatio="xMidYMid meet"
152→      pointerEvents="none"
153→    />
154→  );
155→}
