342→export function buildSheetScene(project, sheet) {
343→  if (!sheet) return null;
344→
345→  const paper = getPaperPreset(sheet.paperSize);
346→  const zones = buildSheetZones(paper);
347→  const sourceEntries = (sheet.viewports || []).map((viewport) => ({
348→    viewport,
349→    source: resolveSheetViewportSource(project, viewport),
350→  }));
351→  const allowAutoLayout = sheet.layoutTemplate !== 'manual';
352→  const autoEntries = allowAutoLayout
353→    ? sourceEntries.filter((entry) => !entry.viewport.lockAutoLayout)
354→    : [];
355→  const manualEntries = sourceEntries.filter((entry) => entry.viewport.lockAutoLayout);
356→  const autoRects = layoutAutoViewports(autoEntries, zones.contentArea);
357→
358→  const sceneViewports = sourceEntries.map((entry) => {
359→    const rect = autoRects.get(entry.viewport.id)
360→      || fitViewportToSheet(entry.viewport, sheet);
361→    return buildViewportScene(entry.viewport, entry.source, sheet, rect);
362→  });
363→
364→  const sheetIndex = (project?.sheets || []).findIndex((entry) => entry.id === sheet.id);
365→
366→  return {
367→    paper,
368→    title: getSheetDisplayLabel(sheet, Math.max(0, sheetIndex)),
369→    border: zones.border,
370→    liveArea: zones.liveArea,
371→    contentArea: zones.contentArea,
372→    footer: zones.footer,
373→    titleBlock: buildTitleBlock(project, sheet, zones.titleBlock, Math.max(0, sheetIndex), sceneViewports),
374→    viewports: sceneViewports,
375→    graphics: {
376→      colors: SHEET_COLORS,
377→      drawing: DRAWING_GRAPHICS,
378→    },
379→    manualViewportCount: manualEntries.length,
380→  };
381→}
