449→export function getDefaultViewportRect(sheet, source, scale = 100, options = {}) {
450→  const paper = getPaperPreset(sheet.paperSize);
451→  const zones = buildSheetZones(paper);
452→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
453→  const sourceWidth = Math.max(1000, bounds.maxX - bounds.minX);
454→  const sourceHeight = Math.max(1000, bounds.maxY - bounds.minY);
455→  const role = options.role || (source.kind === '3d_preview' ? 'supplemental' : 'primary');
456→  const baseScale = source.kind === '3d_preview' ? 1 : Math.max(1, scale);
457→  const width = clamp(
458→    source.kind === '3d_preview'
459→      ? zones.contentArea.width * 0.72
460→      : (sourceWidth / baseScale) + SHEET_TOKENS.viewportPadding * 2,
461→    role === 'primary' ? 120 : 84,
462→    role === 'primary' ? zones.contentArea.width * 0.72 : zones.contentArea.width * 0.44
463→  );
464→  const height = clamp(
465→    source.kind === '3d_preview'
466→      ? zones.contentArea.height * 0.54
467→      : (sourceHeight / baseScale) + SHEET_TOKENS.viewportPadding * 2,
468→    role === 'primary' ? 96 : 72,
469→    role === 'primary' ? zones.contentArea.height * 0.78 : zones.contentArea.height * 0.42
470→  );
471→
472→  return snapRectToGrid({
473→    x: zones.contentArea.x + SHEET_TOKENS.viewportGutter,
474→    y: zones.contentArea.y + SHEET_TOKENS.viewportGutter,
475→    width,
476→    height,
477→  });
478→}
