 18→function boundsFromPoints(points = [], fallback = { minX: -1000, maxX: 1000, minY: -1000, maxY: 1000 }) {
 19→  if (!points.length) return fallback;
 20→  return {
 21→    minX: Math.min(...points.map((point) => point.x)),
 22→    maxX: Math.max(...points.map((point) => point.x)),
 23→    minY: Math.min(...points.map((point) => point.y)),
 24→    maxY: Math.max(...points.map((point) => point.y)),
 25→  };
 26→}
 27→
 28→function expandBounds(bounds, paddingX, paddingY = paddingX) {
 29→  return {
 30→    minX: bounds.minX - paddingX,
 31→    maxX: bounds.maxX + paddingX,
 32→    minY: bounds.minY - paddingY,
 33→    maxY: bounds.maxY + paddingY,
 34→  };
 35→}
 36→
 37→function collectPlanPoints(floor) {
 38→  const points = [];
 39→
 40→  for (const wall of floor.walls || []) {
 41→    points.push(...(getWallRenderData(wall, floor.columns || []).outline || []));
 42→  }
 43→  for (const room of floor.rooms || []) {
 44→    points.push(...(room.points || []));
 45→  }
 46→  for (const beam of floor.beams || []) {
 47→    const renderData = getBeamRenderData(beam, floor.columns || []);
 48→    if (renderData?.outline) points.push(...renderData.outline);
 49→  }
 50→  for (const stair of floor.stairs || []) {
 51→    const renderData = getStairRenderData(stair);
 52→    if (renderData?.outline) points.push(...renderData.outline);
 53→  }
 54→  for (const landing of floor.landings || []) {
 55→    points.push(...landingOutline(landing));
 56→  }
 57→  for (const column of floor.columns || []) {
 58→    points.push(...columnOutline(column));
 59→  }
 60→  for (const slab of (floor.slabs || [])) {
 61→    const rd = getSlabRenderData(slab);
 62→    if (rd?.boundaryPoints) points.push(...rd.boundaryPoints);
 63→  }
 64→  for (const sc of (floor.sectionCuts || [])) {
 65→    points.push(sc.startPoint, sc.endPoint);
 66→    const renderData = getSectionCutRenderData(sc);
 67→    if (renderData?.arrow) {
 68→      points.push(renderData.arrow.shaftStart, renderData.arrow.shaftEnd, renderData.arrow.headA, renderData.arrow.headB);
 69→    }
 70→  }
 71→
 72→  for (const door of floor.doors || []) {
 73→    const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
 74→    if (!wall) continue;
 75→    const outline = doorOutlineOnWall(wall, door);
 76→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 77→  }
 78→
 79→  for (const windowItem of floor.windows || []) {
 80→    const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
 81→    if (!wall) continue;
 82→    const outline = windowOutlineOnWall(wall, windowItem);
 83→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 84→  }
 85→
 86→  return points;
 87→}
 88→
 89→function buildPlanSource(floor) {
 90→  if (!floor) {
 91→    return {
 92→      kind: 'empty',
 93→      title: 'Plan',
 94→      message: 'Missing floor.',
 95→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
 96→    };
 97→  }
 98→
 99→  const geometryBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);
100→
101→  return {
102→    kind: 'plan',
103→    title: `${floor.name} Plan`,
104→    floor,
105→    bounds: geometryBounds,
106→  };
107→}
108→
109→function sceneBoundsToRenderBounds(scene) {
110→  return {
111→    minX: scene.bounds.minX - VERTICAL_PADDING,
112→    maxX: scene.bounds.maxX + VERTICAL_PADDING,
113→    minY: -scene.bounds.maxZ - TOP_PADDING,
114→    maxY: -scene.bounds.minZ + VERTICAL_PADDING,
115→  };
116→}
