118→function buildSectionSource(project, floor, sourceRefId) {
119→  const cuts = floor?.sectionCuts || [];
120→  const sectionCut = sourceRefId
121→    ? cuts.find(s => s.id === sourceRefId)
122→    : cuts[0] || null;
123→
124→  if (!sectionCut) {
125→    return {
126→      kind: 'empty',
127→      title: 'Section',
128→      message: 'No section cut on this floor.',
129→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
130→    };
131→  }
132→
133→  const scene = buildProjectSectionScene(project, floor.id, sectionCut.id);
134→  return {
135→    kind: 'section',
136→    title: sectionCut.label || 'Section',
137→    floor,
138→    scene,
139→    bounds: sceneBoundsToRenderBounds(scene),
140→  };
141→}
142→
143→function buildElevationSource(project, floor, sourceView) {
144→  if (!floor) {
145→    return {
146→      kind: 'empty',
147→      title: 'Elevation',
148→      message: 'Missing floor.',
149→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
150→    };
151→  }
152→
153→  const scene = buildProjectElevationScene(project, floor.id, sourceView);
154→  const annotationScene = buildElevationAnnotationScene(floor, scene);
155→
156→  return {
157→    kind: 'elevation',
158→    title: scene.title,
159→    floor,
160→    viewMode: sourceView,
161→    scene,
162→    annotationScene,
163→    bounds: sceneBoundsToRenderBounds(scene),
164→  };
165→}
166→
167→function build3DPreviewSource(project, floor) {
168→  if (!floor) {
169→    return {
170→      kind: 'empty',
171→      title: 'Axonometric View',
172→      message: 'Missing floor.',
173→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
174→    };
175→  }
176→
177→  // Use 16:10 aspect ratio matching render resolution (1600x1000).
178→  // At scale 100, this fills a 160x100mm viewport on paper.
179→  const imageWidth = 16000;
180→  const imageHeight = 10000;
181→
182→  return {
183→    kind: '3d_preview',
184→    title: 'Axonometric View',
185→    project,
186→    activeFloorId: floor.id,
187→    bounds: {
188→      minX: 0,
189→      maxX: imageWidth,
190→      minY: 0,
191→      maxY: imageHeight,
192→    },
193→  };
194→}
