537→        };
538→      });
539→    case 'COLUMN_DELETE':
540→      return updateFloor(state, action.floorId, f => ({
541→        ...f,
542→        columns: (f.columns || []).filter(c => c.id !== action.columnId),
543→        walls: f.walls.map(w => detachColumnAttachments(w, f.columns || [], action.columnId)),
544→        beams: (f.beams || []).filter(beam => (
