  1→import { distance } from '@/geometry/point';
  2→import { doorOutlineOnWall, windowOutlineOnWall, wallLength, projectPointOnWall } from '@/geometry/wallGeometry';
  3→import { pointInPolygon } from '@/geometry/polygon';
  4→import { columnOutline } from '@/geometry/columnGeometry';
  5→import { getBeamRenderData } from '@/geometry/beamGeometry';
  6→import { getStairRenderData } from '@/geometry/stairGeometry';
  7→import { landingContainsPoint } from '@/geometry/landingGeometry';
  8→import { fixtureContainsPoint } from '@/geometry/fixtureGeometry';
  9→import { slabContainsPoint } from '@/geometry/slabGeometry';
 10→import { hitTestAnnotation } from '@/annotations/scene';
 11→import { MIN_WALL_LENGTH, SNAP_DISTANCE_PX } from '@/domain/defaults';
 12→import { getWallRenderData, resolveWallEndpoints, snapWallEndpoint } from '@/geometry/wallColumnGeometry';
 13→import { duplicateColumn } from '@/domain/columnModels';
 14→import { hitTestSectionCut } from '@/geometry/sectionCutGeometry';
 15→import { collectPlanRegionSelection, normalizeRectBounds, rectSize } from '@/clipboard/planClipboard';
 16→
 17→function hitTest(modelPos, floor, annotationTolerance) {
 18→  // Hit test doors first (smaller targets, higher priority)
 19→  for (const door of floor.doors) {
 20→    const wall = floor.walls.find(w => w.id === door.wallId);
 21→    if (!wall) continue;
 22→    const info = doorOutlineOnWall(wall, door);
 23→    const poly = [info.p1, info.p2, info.p3, info.p4];
 24→    if (pointInPolygon(modelPos, poly)) {
 25→      return { id: door.id, type: 'door' };
 26→    }
 27→  }
 28→
 29→  // Hit test windows
 30→  for (const win of floor.windows) {
 31→    const wall = floor.walls.find(w => w.id === win.wallId);
 32→    if (!wall) continue;
 33→    const info = windowOutlineOnWall(wall, win);
 34→    const poly = [info.p1, info.p2, info.p3, info.p4];
 35→    if (pointInPolygon(modelPos, poly)) {
 36→      return { id: win.id, type: 'window' };
 37→    }
 38→  }
 39→
 40→  // Hit test walls
 41→  // Hit test columns
 42→  for (const sc of (floor.sectionCuts || [])) {
 43→    if (hitTestSectionCut(modelPos, sc, annotationTolerance)) {
 44→      return { id: sc.id, type: 'sectionCut' };
 45→    }
 46→  }
 47→
 48→  for (const column of (floor.columns || [])) {
 49→    const outline = columnOutline(column);
 50→    if (pointInPolygon(modelPos, outline)) {
 51→      return { id: column.id, type: 'column' };
 52→    }
 53→  }
 54→
 55→  // Hit test fixtures
 56→  for (const fixture of (floor.fixtures || [])) {
 57→    if (fixtureContainsPoint(fixture, modelPos)) {
 58→      return { id: fixture.id, type: 'fixture' };
 59→    }
 60→  }
 61→
 62→  // Hit test beams
 63→  for (const beam of (floor.beams || [])) {
 64→    const renderData = getBeamRenderData(beam, floor.columns || []);
 65→    if (!renderData) continue;
 66→    if (pointInPolygon(modelPos, renderData.outline)) {
 67→      return { id: beam.id, type: 'beam' };
 68→    }
 69→  }
 70→
 71→  // Hit test walls
 72→  for (const wall of floor.walls) {
 73→    const outline = getWallRenderData(wall, floor.columns || []).outline;
 74→    if (pointInPolygon(modelPos, outline)) {
 75→      return { id: wall.id, type: 'wall' };
 76→    }
 77→  }
 78→
 79→  // Hit test stairs after walls/beams/columns so current editing priority stays intact.
 80→  for (const stair of (floor.stairs || [])) {
 81→    const renderData = getStairRenderData(stair);
 82→    if (!renderData) continue;
 83→    if (pointInPolygon(modelPos, renderData.outline)) {
 84→      return { id: stair.id, type: 'stair' };
 85→    }
 86→  }
 87→
 88→  // Hit test landings
 89→  for (const landing of (floor.landings || [])) {
 90→    if (landingContainsPoint(landing, modelPos)) {
 91→      return { id: landing.id, type: 'landing' };
 92→    }
 93→  }
 94→
 95→  // Hit test rooms (lowest priority)
 96→  for (const room of floor.rooms) {
 97→    if (room.points?.length >= 3 && pointInPolygon(modelPos, room.points)) {
 98→      return { id: room.id, type: 'room' };
 99→    }
100→  }
101→
102→  for (const slab of (floor.slabs || [])) {
103→    if (slabContainsPoint(slab, modelPos)) {
104→      return { id: slab.id, type: 'slab' };
105→    }
106→  }
107→
108→  const annotationHit = hitTestAnnotation(modelPos, floor, annotationTolerance);
109→  if (annotationHit) {
110→    return annotationHit;
111→  }
112→
113→  return null;
114→}
