100→export function formatSheetDate(value) {
101→  if (!value) return '';
102→  const date = new Date(value);
103→  if (Number.isNaN(date.getTime())) return String(value);
104→  const year = date.getFullYear();
105→  const month = String(date.getMonth() + 1).padStart(2, '0');
