135→export function resolveSheetScaleLabel(sheet, viewports = []) {
136→  if (sheet?.scaleMode === 'as_noted') return 'As noted';
137→  if (sheet?.scaleMode === 'per_viewport') return 'As noted';
138→
139→  const explicit = sheet?.scaleLabel?.trim();
140→  if (explicit) return explicit;
141→
142→  const scales = [...new Set(viewports
143→    .filter((viewport) => viewport.source?.kind !== '3d_preview')
144→    .map((viewport) => Math.max(1, Math.round(Number(viewport.scale) || 100))) )];
